/*
 * Redoc docs UI enhancer:
 * - Detects request sample tab groups generated by Redoc.
 * - Replaces the tab strip with two dropdowns (client + example variant).
 * - Supports Payload, Python, q/qAPI/q/IPC, and cURL labels.
 *
 * Note: this relies on Redoc's rendered tab DOM and may need updates if Redoc markup changes.
 */
(function () {
  function parseLabel(label) {
    var l = (label || '').trim();
    var m = l.match(/^(Payload|Python|q(?:API)?|q\/IPC|cURL)(?:\s*\((.+)\))?$/i);
    if (!m) return null;
    var raw = m[1];
    var client = raw;
    if (/^payload$/i.test(raw)) client = 'Payload';
    else if (/^python$/i.test(raw)) client = 'Python';
    else if (/^curl$/i.test(raw)) client = 'cURL';
    else client = 'q';

    return {
      client: client,
      variant: (m[2] || 'default').trim(),
    };
  }

  function getTabEls(container) {
    return Array.from(
      container.querySelectorAll('[data-rttab="true"], li[role="tab"], button[role="tab"]')
    ).filter(function (el) {
      return (el.textContent || '').trim().length > 0;
    });
  }

  function activateTab(el) {
    el.click();
    el.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
  }

  function convertOne(tabContainer) {
    if (!tabContainer || tabContainer.dataset.codexTwoDropdownApplied === '1') return;

    var tabs = getTabEls(tabContainer);
    if (tabs.length < 2) return;

    var map = {};
    var clients = [];
    var variants = [];
    var parsedCount = 0;

    tabs.forEach(function (tab) {
      var parsed = parseLabel((tab.textContent || '').trim());
      if (!parsed) return;
      parsedCount++;
      if (!clients.includes(parsed.client)) clients.push(parsed.client);
      if (!variants.includes(parsed.variant)) variants.push(parsed.variant);
      map[parsed.client + '::' + parsed.variant] = tab;
    });

    // Only transform request sample groups where language clients exist.
    if (parsedCount < 2) return;
    if (!clients.includes('Python') || !clients.includes('cURL')) return;

    var host = tabContainer.parentElement;
    if (!host) return;

    var wrapper = document.createElement('div');
    wrapper.className = 'codex-two-select-wrap';

    var clientSelect = document.createElement('select');
    clientSelect.setAttribute('aria-label', 'Client');
    clients.forEach(function (c) {
      var o = document.createElement('option');
      o.value = c;
      o.textContent = c;
      clientSelect.appendChild(o);
    });

    var variantSelect = document.createElement('select');
    variantSelect.setAttribute('aria-label', 'Example');

    function syncVariantOptions() {
      var selectedClient = clientSelect.value;
      var allowed = variants.filter(function (v) {
        return !!map[selectedClient + '::' + v];
      });

      if (allowed.length === 0) allowed = ['default'];

      var keep = allowed.includes(variantSelect.value) ? variantSelect.value :
        (allowed.includes('basic') ? 'basic' :
        allowed.includes('quick') ? 'quick' :
        allowed.includes('default') ? 'default' : allowed[0]);

      variantSelect.innerHTML = '';
      allowed.forEach(function (v) {
        var o = document.createElement('option');
        o.value = v;
        o.textContent = v;
        variantSelect.appendChild(o);
      });
      variantSelect.value = keep;
    }

    function applySelection() {
      var key = clientSelect.value + '::' + variantSelect.value;
      var target = map[key];
      if (!target) {
        target = map[clientSelect.value + '::default'] || tabs[0];
      }
      if (target) activateTab(target);
    }

    clientSelect.addEventListener('change', function () {
      syncVariantOptions();
      applySelection();
    });
    variantSelect.addEventListener('change', applySelection);

    // default: Payload first, then Python, then q, else first
    clientSelect.value = clients.includes('Payload')
      ? 'Payload'
      : (clients.includes('Python')
          ? 'Python'
          : (clients.includes('q') ? 'q' : clients[0]));
    syncVariantOptions();

    wrapper.appendChild(clientSelect);
    wrapper.appendChild(variantSelect);

    // Insert before original tab list and hide only tab strip (not panels)
    var tabList = tabContainer.querySelector('.react-tabs__tab-list');
    if (tabList) {
      host.insertBefore(wrapper, tabContainer);
      tabList.style.display = 'none';
    } else {
      host.insertBefore(wrapper, tabContainer);
    }

    tabContainer.dataset.codexTwoDropdownApplied = '1';
    applySelection();
  }

  function scan() {
    var tabContainers = Array.from(document.querySelectorAll('[data-rttabs="true"]'));
    tabContainers.forEach(convertOne);
  }

  var mo = new MutationObserver(scan);

  function init() {
    scan();
    mo.observe(document.body, { childList: true, subtree: true });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
